mapper.select:
SELECT i.inq_no, i.member_no, i.title, i.inq_status, i.reply_dt, i.created_at, i.updated_at, m.email AS member_email, m.member_nm, c.code_nm AS inq_status_nm FROM inquiry i LEFT JOIN member m ON i.member_no = m.member_no LEFT JOIN com_code c ON c.grp_cd = 'INQ_STATUS' AND c.code = i.inq_status
AND i.member_no = #{memberNo}
AND i.inq_status = #{searchStatus}
AND ( i.title LIKE CONCAT('%', #{searchKeyword}, '%') OR m.email LIKE CONCAT('%', #{searchKeyword}, '%') OR m.member_nm LIKE CONCAT('%', #{searchKeyword}, '%') )
ORDER BY i.inq_no DESC
